def _get_sample_text(sample: dict) -> str:
    return sample.get("script", "") or sample.get("title", "") or sample.get("text", "") or sample.get("content", "")


def _is_safe_few_shot_sample(sample: dict, sample_type: str) -> bool:
    text = _get_sample_text(sample)
    if not text:
        return False
    patterns = _RISKY_FEW_SHOT_PATTERNS.get("common", ()) + _RISKY_FEW_SHOT_PATTERNS.get(sample_type, ())
    return not any(re.search(pattern, text) for pattern in patterns)


