def get_few_shot_samples(
    category: str,
    sample_type: str = "script",
    count: int = 3,
    prefer_validated: bool = True,
) -> list[dict]:
    """
    获取指定品类的Few-shot样本，注入Prompt用。

    参数：
        category: 品类名（如"脐橙"/"草莓"/"通用"）
        sample_type: 样本类型（script/topic/live_module）
        count: 需要的样本数量
        prefer_validated: 优先返回商家验证过的样本

    返回：
        [{"script": "...", "hook_type": "...", "source": "..."}, ...]
        如果样本不足，返回空列表（调用方需处理空列表情况）
    """
    candidates: list[dict] = []

    # 1. 优先从已验证样本取
    if prefer_validated and category in _VALIDATED_SAMPLES:
        candidates.extend(_VALIDATED_SAMPLES[category])

    # 2. 从基础样本库取
    cat_samples = SAMPLES.get(category, {}).get(sample_type, [])
    candidates.extend(cat_samples)

    # 3. 兜底：从通用库取
    if len(candidates) < count:
        general = SAMPLES.get("通用", {}).get(sample_type, [])
        candidates.extend(general)

    # 优先返回 usable_direct=True 的样本
    usable = [s for s in candidates if s.get("usable_direct", True)]
    pool = usable if usable else candidates
    safe_pool = [s for s in pool if _is_safe_few_shot_sample(s, sample_type)]
    pool = safe_pool if safe_pool else pool

    if not pool:
        return []

    # 优先选 verified_hit 真实爆款，剩余名额随机补
    verified = [s for s in pool if s.get("verified_hit")]
    non_verified = [s for s in pool if not s.get("verified_hit")]

    selected: list[dict] = []
    if len(verified) >= count:
        return random.sample(verified, count)
    if verified:
        pick_v = len(verified)
        if non_verified:
            pick_v = max(1, count - 1)
        if count == 3 and len(verified) >= 2:
            pick_v = max(pick_v, 2)
        pick_v = min(pick_v, len(verified), count)
        selected.extend(random.sample(verified, pick_v))
    remaining = count - len(selected)
    if remaining > 0 and non_verified:
        selected.extend(random.sample(non_verified, min(remaining, len(non_verified))))

    # 兜底：如果 verified 不够也没 non_verified，从 pool 随机取
    if len(selected) < count:
        rest = [s for s in pool if s not in selected]
        selected.extend(random.sample(rest, min(count - len(selected), len(rest))))

    return selected


def add_validated_sample(category: str, script: str, source: str = "merchant_feedback") -> None:
    """
    商家标记「直接可用」后，自动将生成内容沉淀到验证样本库。
    由 feedback_router.py 调用。
    """
    if category not in _VALIDATED_SAMPLES:
        _VALIDATED_SAMPLES[category] = []

    _VALIDATED_SAMPLES[category].append({
        "script": script,
        "hook_type": "未分类",
        "source": source,
        "views_approx": 0,
        "usable_direct": True,
    })


def format_few_shot_block(samples: list[dict], sample_type: str = "script") -> str:
    """
    将样本列表格式化为Prompt注入文本块。

    示例输出：
        【真实爆款样本①】
        家人们！超市卖12块一斤，今天产地直发...
        （钩子类型：价格冲击 | 来源：抖音三农真实案例）

        【真实爆款样本②】
        ...
    """
    if not samples:
        return ""

    type_labels = {
        "script": "爆款口播",
        "topic": "爆款选题标题",
        "live_module": "直播话术",
        "pain_point": "痛点分析",
        "reply": "客服回复",
    }
    label = type_labels.get(sample_type, "样本")
    lines = [f"【参考以下{len(samples)}条真实{label}，生成同风格、同结构的内容，禁止书面语，必须口语化、产地化】\n"]
    for i, s in enumerate(samples, 1):
        hook = s.get("hook_type", "")
        hook_str = f"（{hook}型）" if hook else ""
        # 支持不同字段名
        text = s.get("script", "") or s.get("title", "") or s.get("text", "") or s.get("content", "")
        lines.append(f"【真实样本{i}{hook_str}】\n{text}\n")

    return "\n".join(lines)


def get_sample_stats() -> dict:
    """返回样本库统计信息（用于仪表盘展示）"""
    total = 0
    verified_hit_count = 0
    by_category: dict[str, int] = {}

    for cat, types in SAMPLES.items():
        cat_count = sum(len(v) for v in types.values())
        total += cat_count
        by_category[cat] = cat_count
        for type_samples in types.values():
            for s in type_samples:
                if isinstance(s, dict) and s.get("verified_hit"):
                    verified_hit_count += 1

    user_validated = 0
    for cat, items in _VALIDATED_SAMPLES.items():
        user_validated += len(items)
        by_category[cat] = by_category.get(cat, 0) + len(items)
        total += len(items)

    return {
        "total_samples": total,
        "validated_samples": verified_hit_count + user_validated,
        "verified_hit_samples": verified_hit_count,
        "user_validated_samples": user_validated,
        "categories_with_samples": sum(1 for v in by_category.values() if v > 0),
        "by_category": by_category,
        "is_ready": total >= 10,
    }
